public JSONArray getMonthlyDisplayedEvents(Calendar today, String apname, User user, RagicBundle bundle, int eventsPerMonth, int topNHitsInSearch,JSONArray result) {
        FTCalendar ftc=new FTCalendar();
        ftc.setMaxNumOfEvents(eventsPerMonth);
        ftc.setTopNHits(topNHitsInSearch);


        SimpleDateFormat yyyymm=new SimpleDateFormat("yyyy/MM");
        String searchString = yyyymm.format(today.getTime());


        try{
            JSONArray ja = ftc.getEvents(apname, searchString, user, bundle, true);
            JSONArray ja_repeat = ftc.getEvents(apname, Const.REPEAT_DATE_INDEX_PREFIX,user, bundle, true);

            for(int i=0;i<ja.length();i++)result.put(ja.getJSONObject(i));
            for(int i = 0; i < ja_repeat.length(); i++) {
                JSONObject calendarEventJSON = ja_repeat.optJSONObject(i);
                if(calendarEventJSON == null) continue;
                List<JSONObject> convertedEvents = convertRepeatEvents(calendarEventJSON, today); // process repeat dates
                for(JSONObject convertedEvent: convertedEvents) result.put(convertedEvent);
            }
        }catch (Exception e){
            new Log("/log/homeCalendar.log").setIfDisplayTime(true).info("homeCalendar:"+e);
        }


        return result;
}




public JSONArray getMonthlyDisplayedEvents(Calendar today, String apname, User user, RagicBundle bundle, int eventsPerMonth, int topNHitsInSearch, Map<String,List<String>>selectedEvents, JSONArray result) {
    FTCalendar ftc=new FTCalendar();
    ftc.setMaxNumOfEvents(eventsPerMonth);
    ftc.setTopNHits(topNHitsInSearch);
    //ftc.setAllowEmptyEntryName(true);

    SimpleDateFormat yyyymm=new SimpleDateFormat("yyyy/MM");
    String searchString = yyyymm.format(today.getTime());

    try{
        ftc.setSheetPath_domainId(selectedEvents);
        JSONArray ja = ftc.getEvents(apname, searchString, user, bundle,true);
        JSONArray ja_repeat = ftc.getEvents(apname, Const.REPEAT_DATE_INDEX_PREFIX,user, bundle, true);

        for(int i=0;i<ja.length();i++)result.put(ja.getJSONObject(i));
        for(int i = 0; i < ja_repeat.length(); i++) {
            JSONObject calendarEventJSON = ja_repeat.optJSONObject(i);
            if(calendarEventJSON == null) continue;
            List<JSONObject> convertedEvents = convertRepeatEvents(calendarEventJSON, today); // process repeat dates
            for(JSONObject convertedEvent: convertedEvents) result.put(convertedEvent);
        }
    }catch (Exception e){
        new Log("/log/homeCalendar.log").setIfDisplayTime(true).info("homeCalendar:"+e);
    }


    return result;
}


public List<JSONObject> convertRepeatEvents(JSONObject calendarEventJSON, Calendar cal_now) {
    List<JSONObject> events = new ArrayList<>();
    String date_init = calendarEventJSON.optString("date_init");
    if(date_init == null) return events;
    
    if(!date_init.startsWith(Const.REPEAT_DATE_INDEX_PREFIX)) {
        events.add(calendarEventJSON);
    } else {
        String calendarEventString = calendarEventJSON.toString();
        // the last day of this month
        Calendar cal_end = Calendar.getInstance();
        cal_end.setTime(cal_now.getTime());
        cal_end.set(Calendar.YEAR, cal_now.get(Calendar.YEAR));
        cal_end.set(Calendar.MONTH, cal_now.get(Calendar.MONTH));
        cal_end.set(Calendar.DAY_OF_MONTH, cal_end.getActualMaximum(Calendar.DAY_OF_MONTH)); 
        cal_end.set(Calendar.HOUR_OF_DAY, cal_end.getActualMaximum(Calendar.HOUR_OF_DAY));
        cal_end.set(Calendar.MINUTE, cal_end.getActualMaximum(Calendar.MINUTE));
        cal_end.set(Calendar.SECOND, cal_end.getActualMaximum(Calendar.SECOND));
        
        List<Date> matchedDates = RepeatDateHelper.getRepeatDates(cal_now.getTime(), cal_end.getTime(), date_init);
        for(Date matechedDate: matchedDates) {
            String matechedDateString = Encoder.formatAsStandardDate(matechedDate, false);
            try {
                JSONObject convertedEvent = new JSONObject(calendarEventString);
                convertedEvent.put("date_init", matechedDateString);
                convertedEvent.put("date_end", matechedDateString);
                events.add(convertedEvent);
            } catch(Exception e) {
                e.printStackTrace();
            }
        }
    }
    return events;
}
